local CS = CS
local typeof = typeof
local typeXUIText = typeof(CS.YXUIText)
local typeUIImage = typeof(UnityEngine.UI.Image)

------------------------------------------------------------------
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class UIIconHyperText:LxNodeBase
local UIIconHyperText = LxClass("UIIconHyperText", LxNodeBase)
------------------------------------------------------------------

UIIconHyperText.GOLD_ICON = "icon_item_gold"
UIIconHyperText.CRIT = "icon_item_gold"

function UIIconHyperText:Create(trans,goldBuyLogDate)
    self._logTrans = CS.FindTrans(trans,"Log")
    if not self._logTrans then
        return
    end
    CS.ShowObject(self._logTrans,true)
    self:InitTrans()
    self:SetDate(goldBuyLogDate)
end

function UIIconHyperText:InitTrans()
    self._iconTrans = CS.FindTrans(self._logTrans,"Icon")
    self._describeTextTrans = CS.FindTrans(self._logTrans,"DescribeText")
    self._text1 = CS.FindTrans(self._describeTextTrans,"Text1")   --花费
    self._text2 = CS.FindTrans(self._describeTextTrans,"Text2")   --许愿获得
    self._setTextTrans = CS.FindTrans(self._logTrans,"SetText")
    self._consumptionCurrencyIconTrans = CS.FindTrans(self._iconTrans,"Icon1") --花费货币图片
    self._getGoldIconTrans = CS.FindTrans(self._iconTrans,"Icon2")             --获得金币图片
    self._criticalStrikeIconTrans = CS.FindTrans(self._iconTrans,"Icon3")      --暴击图片
    self._consumptionCurrencyText = CS.FindTrans(self._setTextTrans,"SetText1")   --花费货币数量
    self._getGoldText = CS.FindTrans(self._setTextTrans,"SetText2")               --获得金币数量
    self._criticalStrikeText = CS.FindTrans(self._setTextTrans,"SetText3")        --暴击倍数

    self._consumptionCurrencyIcon = self._consumptionCurrencyIconTrans:GetComponent(typeUIImage)
    self._getGoldIcon = self._getGoldIconTrans:GetComponent(typeUIImage)
    self._criticalStrikeIcon = self._criticalStrikeIconTrans:GetComponent(typeUIImage)
    self._consumptionCurrency = self._consumptionCurrencyText:GetComponent(typeXUIText)
    self._getGold = self._getGoldText:GetComponent(typeXUIText)
    self._criticalStrike = self._criticalStrikeText:GetComponent(typeXUIText)

    self:SetTextContent(self._text1,ccClientText(13004))
    self:SetTextContent(self._text2,ccClientText(13005))


    CS.ShowObject(self._criticalStrikeIconTrans,false)
    CS.ShowObject(self._criticalStrikeText,false)
end

function UIIconHyperText:SetTextContent(tran,str)
    self:SetXTextContent(tran,str)
end

function UIIconHyperText:SetDate(goldBuyLogDate)
    if not goldBuyLogDate then
        return
    end

    local icon = gModelGoldBuy:GetBuyNeedItemIconByRefId(goldBuyLogDate.redId)
    if icon then
        self:SetImageImage(self._consumptionCurrencyIcon,icon)
    end

    self:SetImageImage(self._getGoldIcon,UIIconHyperText.GOLD_ICON)
    if goldBuyLogDate.buyTime and goldBuyLogDate.buyTime~= "" then -- 购买次数
        local cost = gModelGoldBuy:GetBuyNeedCountByRefId(goldBuyLogDate.redId,nil,nil,goldBuyLogDate.buyTime)
        local str = cost and LUtil.NumberCoversion(cost) or 0
        self:SetTextContent(self._consumptionCurrencyText,str)

    end
    if goldBuyLogDate.gold then
        local value = LUtil.NumberCoversion(goldBuyLogDate.gold)
        self:SetTextContent(self._getGoldText,value)
    end

    if goldBuyLogDate.crit > 1 then
        CS.ShowObject(self._criticalStrikeIconTrans,true)
        CS.ShowObject(self._criticalStrikeText,true)
        if goldBuyLogDate.crit then
            local str = string.format("X%.1f",goldBuyLogDate.crit)
            self:SetTextContent(self._criticalStrikeText,str)
        end
    end
end

function UIIconHyperText:Destroy()
    LxNodeBase.Dispose(self)
end




return UIIconHyperText